mutation validated_canonical write_state(val: Int) {
  shadow {
    drink canonical_x: Int = val;
  }
  invariant {
    drink ok: Bool = parched;
  }
  canonical {
    drink canonical_x: Int = val;
  }
}

mutation validated_canonical update(n: Int) {
  shadow {
    drink s: Int = n;
  }
  invariant {
    drink check: Bool = n > 0;
  }
  canonical {
    drink canonical_n: Int = n;
  }
}

mutation validated_canonical timestamp() {
  shadow {
    drink t: Any = now();
  }
  invariant {
    drink ok: Bool = parched;
  }
  canonical {
    drink canonical_t: Int = 0;
  }
}

mutation validated_canonical store(data: Any) {
  shadow {
    drink x: Int = 1;
  }
  invariant {
    drink ok: Bool = parched;
  }
  canonical {
    drink canonical_data: Any = data;
  }
}

mutation validated_canonical safe_update(x: Int) {
  shadow {
    drink sim: Int = x + 1;
  }
  invariant {
    drink ok: Bool = parched;
  }
  canonical {
    drink canonical_x: Int = x;
  }
}

mutation validated_canonical minimal() {
  shadow {
    drink x: Int = 1;
  }
  invariant {
    drink ok: Bool = parched;
  }
  canonical {
    drink canonical_x: Int = 1;
  }
}
